                 }`}
               >
                 <PenTool size={14} /> Đơn thủ công
               </button>

               <button 
                 onClick={() => setShowExpressOnly(!showExpressOnly)}
                 className={`flex items-center gap-2 px-3 py-2 border rounded-lg text-xs font-bold transition-all whitespace-nowrap ${
                   showExpressOnly ? 'bg-red-600 border-red-600 text-white shadow-md animate-pulse' : 'bg-white border-slate-300 text-slate-600'
                 }`}
               >
                 <Zap size={14} fill={showExpressOnly ? "currentColor" : "none"} /> Hỏa Tốc
               </button>

               <div className="flex gap-2 w-full sm:w-auto">
                  <select 
                    value={selectedCarrier}
                    onChange={(e) => setSelectedCarrier(e.target.value)}
                    className="flex-1 sm:w-32 px-3 py-2 bg-white border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                  >
                    <option value="all">Tất cả ĐVVC</option>
                    {availableCarriers.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                  <select 
                    value={selectedShop}
                    onChange={(e) => setSelectedShop(e.target.value)}
                    className="flex-1 sm:w-32 px-3 py-2 bg-white border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                  >
                    <option value="all">Tất cả Shop</option>
                    {availableShops.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                  <select 
                    value={selectedPlatform === 'Manual' ? 'all' : selectedPlatform}
                    onChange={(e) => setSelectedPlatform(e.target.value as any)}
                    className="flex-1 sm:w-32 px-3 py-2 bg-white border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                  >
                    <option value="all">Tất cả sàn</option>
                    {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                  </select>
               </div>

               <div className="relative w-full sm:w-48">
                 <input 
                    type="text" 
                    placeholder="Tìm đơn..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-8 pr-4 py-2 bg-slate-50 border border-slate-300 rounded-lg text-xs font-medium focus:ring-2 focus:ring-indigo-500 transition-all focus:bg-white"
                 />
                 <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
               </div>
            </div>
         </div>
      </div>

      {/* Orders Container */}
      <div className="flex-1 space-y-4">
         {/* Desktop Column Header - Updated to Light Theme */}
         <div className="hidden lg:grid grid-cols-12 gap-4 px-6 py-3 bg-indigo-50 border border-indigo-100 text-indigo-900 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-sm">
            <div className="col-span-5 flex items-center gap-4">
              <div className="w-8 flex justify-center">
                 <input type="checkbox" checked={selectedOrderIds.size === currentItems.length && currentItems.length > 0} onChange={toggleSelectAll} className="rounded w-4 h-4 text-indigo-600 focus:ring-indigo-500 border-slate-300 cursor-pointer" />
              </div>
              <span>Sản phẩm & Thông tin kiện hàng</span>
            </div>
            <div className="col-span-2 text-center">Yêu cầu từ khách</div>
            <div className="col-span-2 text-center">Tài chính (Tạm tính)</div>
            <div className="col-span-3 text-center">Vận chuyển & Thao tác</div>
         </div>

         {currentItems.length === 0 ? (
           <div className="text-center py-20 bg-white rounded-2xl border-2 border-dashed border-slate-200">
              <ShoppingBag size={64} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">Không có đơn hàng nào khớp với bộ lọc</p>
              <button onClick={() => { setActiveTab('all'); setSearchTerm(''); setSelectedPlatform('all'); }} className="mt-4 text-indigo-600 font-bold hover:underline text-sm">Xóa tất cả bộ lọc</button>
           </div>
         ) : (
           currentItems.map(order => {
             const isExpanded = expandedOrderIds.has(order.id);
             const visibleItems = isExpanded ? order.items : order.items.slice(0, 1);
             const hiddenCount = order.items.length - 1;

             return (
             <div 
               key={order.id} 
               className={`bg-white border-2 rounded-2xl shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden group 
                 ${selectedOrderIds.has(order.id) ? 'border-indigo-400 ring-4 ring-indigo-50' : order.shippingMethod === 'Hỏa tốc' ? 'border-red-200' : 'border-slate-100'}
                 ${order.shippingMethod === 'Hỏa tốc' ? 'bg-red-50/30' : ''}
               `}
             >
                {/* Order Header Row */}
                <div className={`px-5 py-3 border-b flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 ${order.shippingMethod === 'Hỏa tốc' ? 'bg-red-50/50 border-red-100' : 'bg-slate-50/40 border-slate-50'}`}>
                   <div className="flex items-center gap-4 w-full sm:w-auto">
                      <input 
                        type="checkbox" 
                        checked={selectedOrderIds.has(order.id)} 
                        onChange={() => toggleSelectOrder(order.id)}
                        className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer shrink-0" 
                      />
                      <div className="flex items-center gap-3 overflow-hidden">
                         <span className="font-black text-sm text-slate-900 truncate">{order.customerName}</span>
                         <span className="text-slate-300">|</span>
                         <PlatformIcon platform={order.platform} />
                         <span className="text-xs font-mono font-bold text-slate-400 bg-white px-2 py-0.5 rounded border border-slate-100">{order.id}</span>

                         {/* View Detail Button */}
                         <button 
                            onClick={() => setSelectedOrderDetail(order)}
                            className="p-1.5 bg-white border border-slate-200 rounded text-slate-500 hover:text-indigo-600 hover:border-indigo-200 transition-colors ml-2"
                            title="Xem chi tiết"
                         >
                            <Eye size={14} />
                         </button>

                         {/* Re-sync Button */}
                         <button 
                            onClick={() => handleResyncOrder(order.id)}
                            disabled={isResyncing === order.id}
                            className="p-1.5 bg-white border border-slate-200 rounded text-slate-500 hover:text-indigo-600 hover:border-indigo-200 transition-colors ml-1 disabled:opacity-50"
                            title="Đồng bộ lại"
                         >
                            {isResyncing === order.id ? <Loader2 size={14} className="animate-spin text-indigo-600"/> : <RefreshCw size={14} />}
                         </button>
                      </div>
                   </div>
                   <div className="flex items-center gap-4 text-xs w-full sm:w-auto justify-between sm:justify-end">
                      <div className="flex items-center gap-1.5 text-slate-500 font-bold">
                        <Clock size={14}/> {order.date}
                      </div>
                      {order.shippingMethod === 'Hỏa tốc' && (
                        <div className="flex items-center gap-1 text-white font-black bg-gradient-to-r from-red-500 to-orange-500 px-3 py-1 rounded-full text-[10px] uppercase shadow-lg shadow-red-200 animate-pulse">
                          <Flame size={12} fill="currentColor" /> HỎA TỐC
                        </div>
                      )}
                   </div>
                </div>

                {/* Order Body Grid */}
                <div className="p-5 grid grid-cols-1 lg:grid-cols-12 gap-6 items-center">
                   {/* Products Column */}
                   <div className="lg:col-span-5 space-y-2">
                      {visibleItems.map((item, idx) => (
                        <div key={idx} className="flex gap-4 items-start bg-slate-50/50 p-2 rounded-xl border border-slate-100/50">
                           <div className="w-16 h-16 rounded-lg border-2 border-white overflow-hidden shrink-0 shadow-sm">
                              <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                           </div>
                           <div className="flex-1 min-w-0 flex flex-col justify-center">
                              <h4 className="text-sm font-bold text-slate-800 line-clamp-1 group-hover:text-indigo-600 transition-colors">{item.name}</h4>
                              <div className="flex flex-wrap gap-2 mt-1.5">
                                <span className="text-[10px] font-bold text-slate-500 bg-white px-2 py-0.5 rounded border border-slate-200">SKU: {item.sku}</span>
                                <span className="text-[10px] font-bold text-indigo-600 bg-white px-2 py-0.5 rounded border border-indigo-100 uppercase">{item.variant}</span>
                              </div>
                              <div className="flex items-center gap-3 mt-2">
                                 <span className="text-sm font-black text-red-600 bg-red-50 px-2 py-0.5 rounded">x{item.quantity}</span>
                                 <span className="text-sm font-black text-slate-900">{formatCurrency(item.price)}</span>
                              </div>
                           </div>
                        </div>
                      ))}

                      {order.items.length > 1 && (
                        <button 
                            onClick={() => toggleOrderExpand(order.id)}
                            className="text-xs text-indigo-600 font-medium hover:underline flex items-center gap-1 w-full pl-2 pt-1 transition-colors"
                        >
                            {isExpanded ? <ChevronUp size={14}/> : <ChevronDown size={14}/>}
                            {isExpanded ? 'Thu gọn' : `Xem thêm ${hiddenCount} sản phẩm khác`}
                        </button>
                      )}
                   </div>

                   {/* Customer Request Column */}
                   <div className="lg:col-span-2 text-sm text-slate-600 h-full flex flex-col justify-center px-2">
                      {order.note ? (
                        <div className="bg-yellow-50/50 border-l-4 border-yellow-400 p-3 rounded-r-xl text-xs text-yellow-900 italic font-medium relative shadow-sm">
                            <MessageSquareQuote size={16} className="absolute -top-2 -right-2 text-yellow-400 opacity-50"/>
                            "{order.note}"
                        </div>
                      ) : (
                        <div className="text-slate-300 text-[10px] font-bold uppercase tracking-widest text-center italic">Không có yêu cầu</div>
                      )}
                   </div>

                   {/* Finance Column */}
                   <div className="lg:col-span-2 bg-indigo-50/30 p-4 rounded-2xl border border-indigo-100/50 space-y-3 h-full flex flex-col justify-center shadow-inner">
                      <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold text-slate-400 uppercase">Khách trả</span>
                        <span className="text-sm font-black text-indigo-700">{formatCurrency(order.total)}</span>
                      </div>
                      <div className="space-y-1 pt-2 border-t border-indigo-100">
                         <div className="flex justify-between items-center text-[10px]">
                            <span className="text-slate-400 font-bold">Phí sàn</span>
                            <span className="text-red-500 font-bold">-{formatCurrency(order.platformFee)}</span>
                         </div>
                         <div className="flex justify-between items-center text-[10px]">
                            <span className="text-slate-400 font-bold">Lợi nhuận</span>
                            <span className="text-green-600 font-black">+{formatCurrency(order.profit)}</span>
                         </div>
                      </div>
                   </div>

                   {/* Shipping & Operations Column */}
                   <div className="lg:col-span-3 h-full flex flex-col justify-center lg:border-l-2 border-slate-50 lg:pl-6 pt-4 lg:pt-0">
                      {renderShippingStatus(order)}
                   </div>
                </div>
             </div>
           )})
         )}
      </div>

      {/* Pagination Footer */}
      {filteredOrders.length > 0 && (
          <div className="px-6 py-5 bg-white rounded-2xl border border-slate-200 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-sm shrink-0">
             <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">
               Hiển thị <span className="text-indigo-600">{indexOfFirstItem + 1}</span> - <span className="text-indigo-600">{Math.min(indexOfLastItem, filteredOrders.length)}</span> trên <span className="text-slate-800">{filteredOrders.length}</span> kết quả
             </div>
             <div className="flex items-center gap-3">
               <button 
                 onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                 disabled={currentPage === 1}
                 className="p-2.5 rounded-xl border-2 border-slate-100 bg-white text-slate-600 disabled:opacity-30 hover:border-indigo-200 hover:text-indigo-600 transition-all shadow-sm active:scale-95"
               >
                 <ChevronLeft size={20} />
               </button>
               <div className="bg-slate-100 px-4 py-2 rounded-xl text-xs font-black text-slate-600">
                 Trang {currentPage} / {totalPages}
               </div>
               <button 
                 onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                 disabled={currentPage === totalPages}
                 className="p-2.5 rounded-xl border-2 border-slate-100 bg-white text-slate-600 disabled:opacity-30 hover:border-indigo-200 hover:text-indigo-600 transition-all shadow-sm active:scale-95"
               >
                 <ChevronRight size={20} />
               </button>
             </div>
          </div>
        )}

      {/* --- Global Modals --- */}

      {bulkAction === 'process' && renderBulkProcessModal()}
      {bulkAction === 'print' && renderBulkPrintModal()}
      {bulkAction === 'export' && renderExportModal()}

      {/* Order Detail Modal */}
      {renderOrderDetailModal()}

      {/* Confirm Order Modal */}
      {renderConfirmOrderModal()}

    </div>
  );
};

export default OrderList;
